import{_ as o,o as e,c as i,a2 as a}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"Impostazioni pagina","description":"","frontmatter":{},"headers":[],"relativePath":"it-IT/Page/page-settings.md","filePath":"it-IT/Page/page-settings.md","lastUpdated":1781962217000}'),d={name:"it-IT/Page/page-settings.md"};function n(r,t,l,s,p,m){return e(),i("div",null,[...t[0]||(t[0]=[a('<h1 id="impostazioni-pagina" tabindex="-1">Impostazioni pagina <a class="header-anchor" href="#impostazioni-pagina" aria-label="Permalink to &quot;Impostazioni pagina&quot;">​</a></h1><p>Le impostazioni pagina controllano aspetto del sito, valori predefiniti della pagina di upload, sfondi e stile del pannello admin.</p><h2 id="impostazioni-globali" tabindex="-1">Impostazioni globali <a class="header-anchor" href="#impostazioni-globali" aria-label="Permalink to &quot;Impostazioni globali&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opzione</th><th>Scopo</th></tr></thead><tbody><tr><td>Titolo sito</td><td>Titolo mostrato nella scheda del browser.</td></tr><tr><td>Icona sito</td><td>Piccola icona mostrata nella scheda del browser.</td></tr><tr><td>Nome ImgBed</td><td>Nome mostrato nelle pagine frontend.</td></tr><tr><td>Logo ImgBed</td><td>Logo mostrato nelle pagine frontend.</td></tr><tr><td>Link logo</td><td>URL aperto cliccando logo o avatar.</td></tr><tr><td>Intervallo cambio sfondo</td><td>Intervallo di rotazione per più sfondi, in millisecondi. <code>60000</code> significa 60 secondi.</td></tr><tr><td>Opacità sfondo</td><td>Opacità dell&#39;immagine di sfondo da <code>0</code> a <code>1</code>. Valori più bassi sono più chiari.</td></tr><tr><td>Prefisso URL predefinito</td><td>Prefisso usato per generare link immagine. Vuoto significa usare il dominio corrente del sito.</td></tr></tbody></table><h2 id="impostazioni-client" tabindex="-1">Impostazioni client <a class="header-anchor" href="#impostazioni-client" aria-label="Permalink to &quot;Impostazioni client&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opzione</th><th>Scopo</th></tr></thead><tbody><tr><td>Annuncio</td><td>Avviso mostrato in alto nella pagina upload. HTML supportato.</td></tr><tr><td>Canale upload predefinito</td><td>Canale selezionato di default nella pagina upload. Puoi anche scegliere Smart Dispatch.</td></tr><tr><td>Directory upload predefinita</td><td>Directory predefinita, per esempio <code>/user/</code>. Vuoto o <code>/</code> significa radice.</td></tr><tr><td>Metodo nome predefinito</td><td>Strategia predefinita per generare il nome file dopo upload. Vedi sotto.</td></tr><tr><td>Converti in WebP di default</td><td>Converte immagini in WebP prima dell&#39;upload.</td></tr><tr><td>Abilita compressione di default</td><td>Comprime immagini localmente nel browser prima dell&#39;upload.</td></tr><tr><td>Soglia compressione predefinita</td><td>Comprimi automaticamente quando un&#39;immagine supera questa dimensione, in MB.</td></tr><tr><td>Dimensione target predefinita</td><td>Dimensione file desiderata dopo compressione, in MB.</td></tr><tr><td>Sfondo pagina login</td><td>Immagine di sfondo per la pagina login utente.</td></tr><tr><td>Sfondo pagina upload</td><td>Immagine di sfondo per la pagina upload.</td></tr><tr><td>Link portale footer</td><td>URL aperto dal pulsante portale nel footer.</td></tr><tr><td>Nascondi footer</td><td>Nasconde il footer frontend quando attivo.</td></tr></tbody></table><h2 id="impostazioni-admin" tabindex="-1">Impostazioni admin <a class="header-anchor" href="#impostazioni-admin" aria-label="Permalink to &quot;Impostazioni admin&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opzione</th><th>Scopo</th></tr></thead><tbody><tr><td>Sfondo login admin</td><td>Immagine di sfondo per la pagina login admin.</td></tr><tr><td>Sfondo admin</td><td>Immagine di sfondo per le pagine admin. Puoi usare un URL o più URL.</td></tr><tr><td>Modalità caricamento immagini</td><td>Modalità anteprima per la lista file admin. Original carica immagini originali. Smart loading preferisce miniature per immagini pubbliche e originali per immagini limitate.</td></tr><tr><td>Origine miniature</td><td>Servizio usato per generare miniature: wsrv.nl, Cloudflare Image Resizing o WordPress Photon. Cloudflare Image Resizing deve essere abilitato in Cloudflare prima di selezionarlo.</td></tr><tr><td>Widget Live2D</td><td>Mostra un personaggio Live2D nel pannello admin.</td></tr><tr><td>Effetto fuochi d&#39;artificio al clic</td><td>Mostra un effetto fuochi d&#39;artificio quando clicchi la pagina.</td></tr><tr><td>Scia stellata cursore</td><td>Mostra una scia di stelle quando muovi il mouse.</td></tr></tbody></table><h2 id="formati-sfondo" tabindex="-1">Formati sfondo <a class="header-anchor" href="#formati-sfondo" aria-label="Permalink to &quot;Formati sfondo&quot;">​</a></h2><p>Sfondo pagina login, sfondo pagina upload e sfondo login admin supportano questi valori:</p><table tabindex="0"><thead><tr><th>Valore</th><th>Effetto</th></tr></thead><tbody><tr><td><code>bing</code></td><td>Usa la rotazione sfondi di Bing.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;,&quot;https://example.com/2.jpg&quot;]</code></td><td>Ruota più immagini.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;]</code></td><td>Usa una singola immagine di sfondo.</td></tr><tr><td><code>[&quot;https://your-domain.com/random?...&quot;]</code></td><td>Usa un link Random Image API. Puoi configurare la tua Random Image API in Altre impostazioni e incollare qui il link generato come singolo sfondo.</td></tr></tbody></table><p>Lo sfondo admin supporta URL immagine. Più URL possono essere separati da virgole inglesi, come indicato nella pagina. Vuoto significa usare lo sfondo predefinito.</p><h2 id="metodo-nome-predefinito" tabindex="-1">Metodo nome predefinito <a class="header-anchor" href="#metodo-nome-predefinito" aria-label="Permalink to &quot;Metodo nome predefinito&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Metodo</th><th>Risultato</th></tr></thead><tbody><tr><td>Default</td><td>Prefisso tempo-casuale + nome originale, per esempio <code>1760000000000_cat.png</code>.</td></tr><tr><td>Solo prefisso</td><td>Prefisso tempo-casuale ed estensione, per esempio <code>1760000000000.png</code>.</td></tr><tr><td>Solo nome originale</td><td>Mantiene il nome originale, per esempio <code>cat.png</code>. Se duplicato, ImgBed aggiunge <code>(1)</code>, <code>(2)</code> e così via.</td></tr><tr><td>Link breve</td><td>Usa un ID breve di 8 caratteri ed estensione, per esempio <code>a1b2c3d4.png</code>.</td></tr></tbody></table>',14)])])}const u=o(d,[["render",n]]);export{g as __pageData,u as default};
